#include <stdio.h>
int fact(int n) {
    if (n <= 1) return 1;
    return n * fact(n-1);
}
int main() {
    printf("%d", fact(7));
    return 0;
}

#include <stdio.h>
struct student {
    char name[10];
    int os;
    int db;
    int hab;
    int hhab;
};
int main() {
    struct student s[3] = {
        {"이순신", 95, 88, 0, 0},
        {"홍길동", 84, 91, 0, 0},
        {"강감찬", 77, 75, 0, 0}
