#include <stdio.h>
int isPerfect(int n) {
    int sum = 0;
    for (int i = 1; i < n; i++) {
        if (n % i == 0) sum += i;
    }
    return sum == n;
}
int main() {
    int total = 0;
    for (int i = 2; i <= 100; i++) {
        if (isPerfect(i)) total += i;
    }
    printf("%d", total);
    return 0;
}

